110	export function claim(input: { items: Item[]; damages: Damage[]; remainingCap?: number }): { payout: number; remainingCap: number } {
111	  const rawPayout = rawPayoutFor(input.items, input.damages);
112	  const availableCap = input.remainingCap ?? CAP_MULTIPLIER * insuranceSumFor(input.items);
113	  const payout = Math.floor(Math.min(rawPayout, availableCap));
114	  return { payout, remainingCap: availableCap - payout };
115	}
