117	export function quote(input: {
118	  yearsWithMHPCO: number;
119	  items: Item[];
120	  applyFirstInsurance?: boolean;
121	  applyFollowUpDiscount?: boolean;
122	}): number {
123	  for (const item of input.items) {
124	    if (!(item.type in BASE_PREMIUM_BY_ITEM_TYPE)) {
125	      throw new Error(`Unknown item type: ${item.type}`);
126	    }
127	  }
128	  const policyBase = policyBaseFor(input.items);
129	  const itemBasesSum = sumOfItemBases(input.items);
130	  return Math.ceil(
131	    policyBase
132	    + firstInsuranceSurchargeFor(input.applyFirstInsurance, input.items)
133	    - loyaltyDiscountFor(input.yearsWithMHPCO, itemBasesSum)
134	    - followUpDiscountFor(input.applyFollowUpDiscount, itemBasesSum)
135	    + PROCESSING_FEE
136	  );
